// draughtsboard@0.2.0 硬依赖 jQuery 全局 + 外链 CSS;先静态 import jQuery→设全局,再动态 import 棋盘(named 导出才是 factory,default 是对象)
import $ from 'https://cdn.jsdelivr.net/npm/jquery@3.7.1/+esm';
globalThis.$ = globalThis.jQuery = $;
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/draughtsboard@0.2.0/draughtsboard.css'; document.head.appendChild(css);
const { DraughtsBoard } = await import('https://cdn.jsdelivr.net/npm/draughtsboard@0.2.0/+esm');
const el = document.getElementById('board'); el.style.width = '100%';
const board = DraughtsBoard(el, { position: data.position ?? 'start', orientation: data.orientation ?? 'white', draggable: data.draggable ?? false });

